class ShoppingCart {
  constructor() {
    this.items = [];
    this.taxRate = 0.08; // 8% tax
    this.discountCode = null;
  }

  addItem(id, price, quantity = 1) {
    if (price < 0) {
      throw new Error('Price cannot be negative');
    }
    if (quantity <= 0) {
      throw new Error('Quantity must be positive');
    }

    const existingItem = this.items.find(item => item.id === id);
    if (existingItem) {
      existingItem.quantity += quantity;
    } else {
      this.items.push({ id, price, quantity });
    }
  }

  removeItem(id) {
    this.items = this.items.filter(item => item.id !== id);
  }

  applyDiscount(code) {
    const discounts = {
      'SAVE10': 0.10,
      'SAVE20': 0.20,
      'SAVE50': 0.50
    };

    if (!discounts[code]) {
      throw new Error('Invalid discount code');
    }

    this.discountCode = code;
  }

  calculateSubtotal() {
    return this.items.reduce((sum, item) => {
      return sum + (item.price * item.quantity);
    }, 0);
  }

  calculateDiscount() {
    if (!this.discountCode) return 0;

    const discounts = {
      'SAVE10': 0.10,
      'SAVE20': 0.20,
      'SAVE50': 0.50
    };

    const subtotal = this.calculateSubtotal();
    return subtotal * discounts[this.discountCode];
  }

  calculateTax() {
    const afterDiscount = this.calculateSubtotal() - this.calculateDiscount();
    return afterDiscount * this.taxRate;
  }

  calculateShipping() {
    const subtotal = this.calculateSubtotal();

    // Free shipping over $50
    if (subtotal >= 50) return 0;
    // $5 shipping for orders under $50
    if (subtotal >= 10) return 5;
    // $10 shipping for orders under $10
    return 10;
  }

  getTotal() {
    const subtotal = this.calculateSubtotal();
    const discount = this.calculateDiscount();
    const tax = this.calculateTax();
    const shipping = this.calculateShipping();

    return Math.round((subtotal - discount + tax + shipping) * 100) / 100;
  }

  isEmpty() {
    return this.items.length === 0;
  }

  clear() {
    this.items = [];
    this.discountCode = null;
  }
}

module.exports = ShoppingCart;

