const ShoppingCart = require('./cart');

describe('ShoppingCart', () => {
  let cart;

  beforeEach(() => {
    cart = new ShoppingCart();
  });

  describe('addItem', () => {
    it('should add a single item to cart', () => {
      cart.addItem(1, 10, 1);
      expect(cart.items.length).toBe(1);
      expect(cart.items[0]).toEqual({ id: 1, price: 10, quantity: 1 });
    });

    it('should throw error for negative price', () => {
      expect(() => cart.addItem(1, -10, 1)).toThrow('Price cannot be negative');
    });

    it('should throw error for zero or negative quantity', () => {
      expect(() => cart.addItem(1, 10, 0)).toThrow('Quantity must be positive');
      expect(() => cart.addItem(1, 10, -5)).toThrow('Quantity must be positive');
    });

    it('should increment quantity if item already exists', () => {
      cart.addItem(1, 10, 2);
      cart.addItem(1, 10, 3);
      expect(cart.items.length).toBe(1);
      expect(cart.items[0].quantity).toBe(5);
    });
  });

  describe('removeItem', () => {
    it('should remove an item from cart', () => {
      cart.addItem(1, 10);
      cart.addItem(2, 20);
      cart.removeItem(1);
      expect(cart.items.length).toBe(1);
      expect(cart.items[0].id).toBe(2);
    });

    it('should not throw error if item does not exist', () => {
      cart.addItem(1, 10);
      expect(() => cart.removeItem(99)).not.toThrow();
    });
  });

  describe('Discount codes', () => {
    it('should apply valid discount code', () => {
      cart.applyDiscount('SAVE10');
      expect(cart.discountCode).toBe('SAVE10');
    });

    it('should throw error for invalid discount code', () => {
      expect(() => cart.applyDiscount('INVALID')).toThrow('Invalid discount code');
    });
  });

  describe('calculateSubtotal', () => {
    it('should return 0 for empty cart', () => {
      expect(cart.calculateSubtotal()).toBe(0);
    });

    it('should calculate correct subtotal for multiple items', () => {
      cart.addItem(1, 10, 2);
      cart.addItem(2, 20, 1);
      expect(cart.calculateSubtotal()).toBe(40);
    });
  });

  describe('calculateDiscount', () => {
    it('should return 0 if no discount applied', () => {
      cart.addItem(1, 100);
      expect(cart.calculateDiscount()).toBe(0);
    });

    it('should calculate 10% discount correctly', () => {
      cart.addItem(1, 100);
      cart.applyDiscount('SAVE10');
      expect(cart.calculateDiscount()).toBe(10);
    });
  });

  describe('calculateTax', () => {
    it('should calculate tax on subtotal minus discount', () => {
      cart.addItem(1, 100);
      cart.applyDiscount('SAVE10');
      const afterDiscount = 100 - 10;
      const expectedTax = afterDiscount * 0.08;
      expect(cart.calculateTax()).toBe(expectedTax);
    });
  });

  describe('calculateShipping', () => {
    it('should be free for orders over $50', () => {
      cart.addItem(1, 60);
      expect(cart.calculateShipping()).toBe(0);
    });

    it('should be $5 for orders $10-$50', () => {
      cart.addItem(1, 25);
      expect(cart.calculateShipping()).toBe(5);
    });

    it('should be $10 for orders under $10', () => {
      cart.addItem(1, 5);
      expect(cart.calculateShipping()).toBe(10);
    });
  });

  describe('getTotal', () => {
    it('should calculate total correctly with all components', () => {
      cart.addItem(1, 100);
      const subtotal = 100;
      const tax = 100 * 0.08;
      const shipping = 0; // Free shipping over $50
      const expected = subtotal + tax + shipping;
      expect(cart.getTotal()).toBe(expected);
    });
  });

  describe('isEmpty and clear', () => {
    it('should return true for empty cart', () => {
      expect(cart.isEmpty()).toBe(true);
    });

    it('should clear cart and discount', () => {
      cart.addItem(1, 10);
      cart.applyDiscount('SAVE10');
      cart.clear();
      expect(cart.isEmpty()).toBe(true);
      expect(cart.discountCode).toBeNull();
    });
  });
});
